import React from 'react';
import { Progress } from 'reactstrap';
import CommonTable, { TableHeader } from './CommonTable';

type Team = {
    team_id: number;
    rating: number;
    wins: number;
    losses: number;
    last_match_time: number;
    name: string;
    tag: string;
    logo_url: string;
}

type TeamsTableProps = {
    teams: Team[];
}

const headers: TableHeader[] = [{ label: "Rank" }, { label: "Name" }, { label: "Rating" }, { label: "Wins" }, { label: "Losses" }];

const getRankString = (rank: number): string => {
    if (rank % 10 == 1) {
        return rank + "st";
    }
    else if (rank % 10 == 2) {
        return rank + "nd";
    }
    else if (rank % 10 == 3) {
        return rank + "rd";
    }
    return rank + "th";
}

const TeamsTable = ({ teams }: TeamsTableProps) => {
    let config = {
        renderTableRowKey: ({ match_id }) => match_id,
        renderTableDataKey: ({ duration }) => duration,
        tableHeaders: [{ label: "Match Id" }, { label: "Duration" }, { label: "Radiant" }, { label: "Dire" }],
        tableData: [
            {
                render: ({ match_id }) => match_id,
            },
            {
                render: ({ tag, logo_url, name }) => {
                    return <><img key={tag} src={logo_url} alt={tag} />{name}</>
                }
            },
            {
                render: ({ rating }) => rating,
            },
            {
                render: ({ wins }) => wins,
            }
        ],
    }
    let rows = teams && teams.slice(0, 100).map((team, index) => {
        return {
            key: team.team_id.toString(),
            data: [
                { value: getRankString(index + 1) },
                { value: <><img key={team.tag} src={team.logo_url} alt={team.tag} />{team.name}</> },
                { value: team.rating },
                { value: team.wins },
                { value: team.losses },
            ]
        }
    });

    // return <CommonTable headers={headers} rows={rows} />
    return <></>
}

export default TeamsTable;